from weasyprint import HTML, CSS

def html_to_pdf(html: str, output_path: str = "../output/cv.pdf"):
    HTML(string=html).write_pdf(
    "cv.pdf",
    stylesheets=[CSS("../templates/cv_fr.css")]
    )


