from pathlib import Path

def fix_photo_path(data: dict) -> dict:
    photo = data.get("Informations personnelles", {}).get("Photo")

    if photo:
        abs_path = Path(photo).resolve()
        data["Informations personnelles"]["Photo"] = f"file://{abs_path}"

    return data
